import{_ as a,o as t,c as o,ag as i}from"./chunks/framework.CMYkYJvz.js";const h=JSON.parse('{"title":"Breakpoint","description":"Pause, inspect, edit, and resume matched HTTP traffic.","frontmatter":{"title":"Breakpoint","description":"Pause, inspect, edit, and resume matched HTTP traffic.","editLink":false},"headers":[],"relativePath":"en/reference/breakpoint.md","filePath":"en/reference/breakpoint.md"}'),r={name:"en/reference/breakpoint.md"};function s(n,e,l,d,p,c){return t(),o("div",null,[...e[0]||(e[0]=[i(`<blockquote><p>This page is automatically synced from <code>docs-en/breakpoint.md</code>. Language: <strong>English</strong> | <a href="./../../reference/breakpoint">中文</a></p></blockquote><h1 id="breakpoint-user-guide" tabindex="-1">Breakpoint User Guide <a class="header-anchor" href="#breakpoint-user-guide" aria-label="Permalink to &quot;Breakpoint User Guide&quot;">​</a></h1><p>Breakpoint pauses selected HTTP requests or responses while Bifrost forwards traffic. You can inspect and edit headers or body, then resume delivery. It is designed for interactive API debugging, upstream parameter verification, downstream response simulation, and temporary rewrite experiments.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Breakpoint has two gates:</p><ol><li>The Breakpoint switch in the Traffic toolbar must be enabled.</li><li>The request must match a rule containing <code>breakpoint://request</code> or <code>breakpoint://response</code>.</li></ol><p>Only enabling the toolbar switch does not pause traffic. Matched pending traffic is released when Breakpoint is disabled.</p><h2 id="web-ui-workflow" tabindex="-1">Web UI Workflow <a class="header-anchor" href="#web-ui-workflow" aria-label="Permalink to &quot;Web UI Workflow&quot;">​</a></h2><ol><li>Open the Web UI and go to Traffic.</li><li>Enable <code>Breakpoint</code> in the toolbar.</li><li>Add a precise rule on the Rules page.</li><li>Send a matching request.</li><li>Open the request detail in Traffic.</li><li>Inspect or edit headers and body in the pause panel.</li><li>Click <code>Resume</code>.</li></ol><h2 id="rule-examples" tabindex="-1">Rule Examples <a class="header-anchor" href="#rule-examples" aria-label="Permalink to &quot;Rule Examples&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>api.example.com/v1/users breakpoint://request</span></span>
<span class="line"><span>api.example.com/v1/users breakpoint://response</span></span>
<span class="line"><span>api.example.com/v1/users breakpoint://request,response</span></span></code></pre></div><p>Supported values: <code>request</code>, <code>req</code>, <code>response</code>, <code>res</code>, <code>both</code>, <code>all</code>, and comma combinations. Keep patterns narrow to avoid blocking unrelated traffic.</p><h2 id="timeout" tabindex="-1">Timeout <a class="header-anchor" href="#timeout" aria-label="Permalink to &quot;Timeout&quot;">​</a></h2><p>The auto-resume timeout is configured in <code>Settings -&gt; Performance</code>. Large, binary, or streaming bodies may be shown as header-only to avoid excessive buffering.</p>`,14)])])}const m=a(r,[["render",s]]);export{h as __pageData,m as default};
